def compute_score() -> tuple[str, float]:
    # Check for added transitions to slide 2
    if len(ppt_diff.modified_transitions) > 1:
        return "Multiple transitions were changed", 0.0

    if ppt_diff.modified_transitions[0][1].slide_id == 'slide2' and ppt_diff.modified_transitions[0][1].transition_type == 'fade':
        return ("'Fade' transition was correctly added to slide 2.", 1.0)
    return ("No 'Fade' transition was added to slide 2.", 0.0)

def compute_score() -> tuple[str, float]:
    t = ppt_diff.modified_transitions[0][1]
    # Typical fade duration in PowerPoint is between 0.5s and 3s
    duration_ok = 0.5 <= t.duration <= 5.0
    # Fade direction should be None or 'in', 'out', etc. but not strictly required
    if duration_ok:
        return (f"Duration for 'Fade' transition is {t.duration:.2f}s, which is appropriate.", 1.0)
    else:
        return (f"Duration for 'Fade' transition is {t.duration:.2f}s, which is out of typical range.", 0.5)

def compute_score() -> tuple[str, float]:
    extraneous = [t for t in ppt_diff.added_transitions if getattr(t, 'slide_number', None) != 2]
    if extraneous:
        slides = ', '.join(str(getattr(t, 'slide_number', getattr(t, 'slide_id', '?'))) for t in extraneous)
        return (f"Extraneous transitions added to slides: {slides}.", 0.0)
    return ("No extraneous transitions were added to other slides.", 1.0)

def compute_score() -> tuple[str, float]:
    # Only allowed: one transition added to slide 2
    # No other additions or modifications
    any_mod = (
        ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations or
        ppt_diff.added_slides or ppt_diff.removed_slides or ppt_diff.modified_slides
    )
    if any_mod:
        return ("There were extraneous modifications to other animations, slides, or transitions.", 0.0)
    return ("No extraneous modifications detected.", 1.0)
